    color: #07c160; /* WeChat brand green */
    flex-shrink: 0;
  }

  .wechat-section__title {
    font-family: var(--font-heading);
    font-size: var(--text-xl);
    font-weight: 700;
    color: var(--color-ink);
    margin: 0;
  }

  .wechat-section__desc {
    font-family: var(--font-body);
    font-size: var(--text-base);
    color: var(--color-body);
