    border: 2px dashed var(--color-stone);
    border-radius: var(--radius-md, 0.5rem);
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    gap: var(--space-2);
    color: var(--color-body);
    background-color: var(--color-bg);
  }

  .wechat-section__qr-icon {
    opacity: 0.4;
  }

  .wechat-section__qr-text {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    opacity: 0.6;
  }

  /* ---------- Contact form ---------- */

  .zh-contact-form-section {
    margin-bottom: var(--space-8);
  }

  .zh-contact-form-section__title {
    font-family: var(--font-heading);
    font-size: var(--text-xl);
    font-weight: 700;
    color: var(--color-ink);
    margin: 0 0 var(--space-2) 0;
  }

  .zh-contact-form-section__desc {
    font-family: var(--font-body);
    font-size: var(--text-base);
    color: var(--color-body);
    margin: 0 0 var(--space-6) 0;
  }

  .zh-contact-form {
    display: flex;
    flex-direction: column;
    gap: var(--space-5);
  }

  .zh-contact-form__field {
    display: flex;
    flex-direction: column;
    gap: var(--space-1);
  }

  .zh-contact-form__label {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    font-weight: 600;
    color: var(--color-ink);
  }

  .zh-contact-form__input {
    font-family: var(--font-body);
    font-size: var(--text-base);
    color: var(--color-ink);
    background-color: var(--color-bg);
    border: 1px solid var(--color-stone);
    border-radius: var(--radius-md, 0.5rem);
    padding: var(--space-3) var(--space-4);
    transition: border-color var(--transition), box-shadow var(--transition);
  }

  .zh-contact-form__input::placeholder {
    color: var(--color-body);
    opacity: 0.5;
  }

  .zh-contact-form__input:focus {
    outline: none;
    border-color: var(--color-terracotta);
    box-shadow: 0 0 0 3px rgba(196, 107, 72, 0.15);
  }

  .zh-contact-form__input--error {
    border-color: var(--color-error, #dc2626);
  }

  .zh-contact-form__textarea {
    resize: vertical;
    min-height: 8rem;
  }

  .zh-contact-form__error {
    font-family: var(--font-body);
    font-size: var(--text-xs, 0.75rem);
    color: var(--color-error, #dc2626);
    min-height: 1.25em;
  }

  .zh-contact-form__submit {
    align-self: flex-start;
    font-family: var(--font-body);
    font-size: var(--text-base);
    font-weight: 600;
    color: var(--color-bg);
    background-color: var(--color-terracotta);
    border: none;
    border-radius: var(--radius-md, 0.5rem);
    padding: var(--space-3) var(--space-8);
    cursor: pointer;
    position: relative;
    transition: background-color var(--transition), transform var(--transition);
  }

  .zh-contact-form__submit:hover:not(:disabled) {
    background-color: #b3654b;
    transform: translateY(-1px);
  }

  .zh-contact-form__submit:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
  }

  .zh-contact-form__submit:disabled {
    opacity: 0.7;
    cursor: not-allowed;
  }

  .zh-contact-form__submit--loading .zh-contact-form__submit-text {
    visibility: hidden;
  }

  .zh-contact-form__spinner {
    display: none;
  }

  .zh-contact-form__submit--loading .zh-contact-form__spinner {
    display: block;
    position: absolute;
    inset: 0;
    margin: auto;
    width: 1.25rem;
    height: 1.25rem;
    border: 2px solid rgba(255, 255, 255, 0.3);
    border-top-color: var(--color-bg);
    border-radius: 50%;
    animation: zh-spin 0.6s linear infinite;
  }

  @keyframes zh-spin {
    to { transform: rotate(360deg); }
  }

  .zh-contact-form__banner {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    padding: var(--space-3) var(--space-4);
    border-radius: var(--radius-md, 0.5rem);
    margin-top: var(--space-2);
  }

  .zh-contact-form__banner[hidden] {
    display: none;
  }

  .zh-contact-form__banner--success {
    background-color: #ecfdf5;
    color: #065f46;
    border: 1px solid #a7f3d0;
  }

  .zh-contact-form__banner--error {
    background-color: #fef2f2;
    color: #991b1b;
    border: 1px solid #fecaca;
  }

  /* ---------- Church info sidebar ---------- */

  .contact-info {
    background-color: var(--color-cream);
    border-radius: var(--radius-md, 0.5rem);
    padding: var(--space-8);
  }

  .contact-info__heading {
    font-family: var(--font-heading);
    font-size: var(--text-lg);
    font-weight: 700;
    color: var(--color-ink);
    margin: 0 0 var(--space-6) 0;
  }

  .contact-info__block {
    margin-bottom: var(--space-6);
  }

  .contact-info__block:last-child {
    margin-bottom: 0;
  }

  .contact-info__label {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    font-weight: 600;
    color: var(--color-ink);
    margin: 0 0 var(--space-1) 0;
  }

  .contact-info__value {
    font-family: var(--font-body);
    font-size: var(--text-sm);
    color: var(--color-body);
    line-height: 1.6;
    margin: 0;
    font-style: normal;
  }

  .contact-info__link {
    color: var(--color-terracotta);
    text-decoration: none;
    transition: color var(--transition);
  }

  .contact-info__link:hover {
    text-decoration: underline;
  }

  .contact-info__link:focus-visible {
    outline: 2px solid var(--color-focus);
    outline-offset: 2px;
    border-radius: 2px;
  }

  /* ---------- Responsive ---------- */

  @media (max-width: 768px) {
    .contact-layout {
      grid-template-columns: 1fr;
      gap: var(--space-10);
    }

    .wechat-section__qr-placeholder {
      width: 10rem;
      height: 10rem;
    }
  }
</style>

